// spheres
float d = (-1.*length(p)+3.)+1.5*noise(p);    
d = min(d, (length(p)-1.5)+1.5*noise(p) );  

// links
float m = 1.5; 
float s = .03;    
d = smin(d, max( abs(p.x)-s, abs(p.y+p.z*.2)-.07 ) , m);          
d = smin(d, max( abs(p.z)-s, abs(p.x+p.y/2.)-.07 ), m );    
d = smin(d, max( abs(p.z-p.y*.4)-s, abs(p.x-p.y*.2)-.07 ), m );    
d = smin(d, max( abs(p.z*.2-p.y)-s, abs(p.x+p.z)-.07 ), m );    
d = smin(d, max( abs(p.z*-.2+p.y)-s, abs(-p.x+p.z)-.07 ), m );
return d;

vec4 result = state;

// Once a ray has hit, keep its result. The remaining bounded iterations are cheap.
if (state.y < 0.5) {
    float t = state.x;
    vec3 ray = normalize(vec3(uv.x, uv.y, 1.0));
    vec3 p = vec3(0.0, 0.0, -3.0) + ray * t;

    p = rotatey(p, iTime / 3.0);

    float mask = max(0.0, 1.0 - length(p / 3.0));
    p = rotatey(p, mask * sin(iTime / 2.0) * 1.2);
    p.y += sin(iTime + p.x) * mask * 0.5;
    p *= 1.1 + sin(iTime / 2.0) * mask * 0.3;

    float d = map(p);
    float done = (d < 0.01 || progress > 0.999) ? 1.0 : 0.0;
    float nextT = done > 0.5 ? t : t + d * 0.5;
    result = vec4(nextT, done, progress, d);
}
return result;

float t = state.x;
vec3 ray = normalize(vec3(uv.x, uv.y, 1.0));
vec3 p = vec3(0.0, 0.0, -3.0) + ray * t;

p = rotatey(p, iTime / 3.0);

float deformMask = max(0.0, 1.0 - length(p / 3.0));
p = rotatey(p, deformMask * sin(iTime / 2.0) * 1.2);
p.y += sin(iTime + p.x) * deformMask * 0.5;
p *= 1.1 + sin(iTime / 2.0) * deformMask * 0.3;

float iter = clamp(state.z, 0.0, 1.0);
float ao = 1.0 - iter;
ao *= ao;
ao = 1.0 - ao;

float glowMask = max(0.0, 1.0 - length(p / 2.0));
glowMask *= abs(sin(iTime * -1.5 + length(p) + p.x) - 0.2);

vec3 color = vec3(0.0);
color += 2.0 * vec3(0.1, 1.0, 0.8) * max(0.0, noise(p) * 4.0 - 2.6) * glowMask;
color += vec3(0.1, 0.5, 0.6) * ao * 6.0;
color += vec3(0.27, 0.2, 0.4) * (t / 8.0);
color = color * 2.0 - 0.15;

vec2 vignetteUv = screenUv;
vignetteUv *= 1.0 - vignetteUv.yx;
float vig = pow(vignetteUv.x * vignetteUv.y * 20.0, 0.25);
color *= vig;
color.y *= 0.8;
color.x *= 1.5;
return color;
